class Solution {public: bool solve(vector<int>& A) {
    stack<int> stack;
    for (int num : A) {
        if (num > A.size())
            return false;
        while (!stack.empty() && stack.top() > num)
            stack.pop();
        stack.push(num);
    }
    return true;
}};

int main() {
    std::ios_base::sync_with_stdio(false);
